def countArrangement(n: int) -> int:
    count = [0]
    visited = [False] * (n + 1)

    def backtrack(index):
        if index > n:
            count[0] += 1
            return

        for num in range(1, n + 1):
            if not visited[num]:
                if num % index == 0 or index % num == 0:
                    visited[num] = True
                    backtrack(index + 1)
                    visited[num] = False

    backtrack(1)
    return count[0]
